  "pattern": {
    "summary": "Recognize floor-division-by-power-of-two idioms expressed as truncating signed division plus a sign/oddness correction term, and fold them to arithmetic right shift.",
    "match": {
      "root": "add",
      "operands": [
        {
          "kind": "sdiv",
          "x": "X",
          "c": "DivC"
        },
        {
          "kind": "sext",
          "from": "i1",
          "to": "type(X/div)",
          "source": {
            "kind": "icmp",
            "predicates": [
              "eq",
              "ugt"
            ],
            "lhs": {
              "kind": "and",
              "x": "X",
              "mask": "Mask"
            },
            "rhs": "CmpConst"
          }
        }
      ],
      "commutative_add": true,
      "type_constraints": [
        "integer scalar or integer vector",
        "DivC is a positive power-of-two integer constant splat",
        "sext result type equals sdiv result type",
        "all operations use the same integer element width"
      ]
    },
    "semantic_intent": "The addend is -1 exactly when X is negative and has any non-zero truncated remainder for division by DivC; adding it to truncating signed division converts it to floor division. For power-of-two divisors, floor signed division equals arithmetic right shift by log2(DivC).",
    "recognized_forms": [
      {
        "icmp_predicate": "ugt",
        "condition": "Mask == SMIN | (DivC - 1), CmpConst == SMIN",
        "meaning": "X is negative and (X & (DivC-1)) != 0"
      },
      {
        "icmp_predicate": "eq",
        "condition": "Currently valid for DivC == 2 with Mask == SMIN + 1 and CmpConst == Mask",
        "meaning": "X is negative and odd"
      }
    ],
